// Normalize + Build Options (must return 1 item)

const raw = $json?.body ?? $json ?? {};

// Accept either direct VP payload OR simple webhook payload
const decision_id = raw.decision_id ?? raw.decisionId ?? raw.id ?? "REQ-0000";
const prompt = raw.prompt ?? raw.title ?? raw.message ?? "No prompt provided";

let options = raw.options;

// If options came in as a string, try to parse (common beginner mistake)
if (typeof options === "string") {
  try {
    options = JSON.parse(options);
  } catch (e) {
    options = null;
  }
}

// Force options to be an array of {id,label}
if (!Array.isArray(options)) {
  return [
    {
      json: {
        ok: false,
        error: "invalid_options",
        hint: "options must be an array like: [{ id:'a', label:'Option A' }]",
        got_type: typeof raw.options,
        got_value: raw.options,
      },
    },
  ];
}

const cleanOptions = options
  .map((o, idx) => ({
    id: String(o?.id ?? idx),
    label: String(o?.label ?? o?.name ?? o?.text ?? `Option ${idx + 1}`),
  }))
  .filter((o) => o.label.trim().length > 0);

if (cleanOptions.length < 2) {
  return [
    {
      json: {
        ok: false,
        error: "not_enough_options",
        hint: "Provide at least 2 options.",
        got: cleanOptions,
      },
    },
  ];
}

// Build the exact backend payload
const vp_payload = {
  decision_id,
  prompt,
  options: cleanOptions,
};

return [
  {
    json: {
      ok: true,
      vp_payload,
    },
  },
];

// Parse VP Result — robust for n8n HTTP Request node variations

const statusCode =
  $json.statusCode ??
  $json.status ??
  null;

// In many n8n configs, the HTTP node returns the JSON body directly as $json
// In other configs, it returns { body: {...}, statusCode: 200 }
const body =
  $json.body ??
  $json;

// Decide “ok” based on the actual response shape coming back from VectorPrime
const ok =
  (statusCode !== null && statusCode >= 200 && statusCode < 300) ||
  (body && typeof body === "object" && Array.isArray(body.ranking));

return [
  {
    json: {
      ok,
      statusCode,
      vp: body,
    },
  },
];

// Create an audit log object (great for reviewers + real-world usage).
const now = new Date().toISOString();

return [{
  json: {
    ok: true,
    audited_at: now,
    decision_id: $json.decision_id,
    engine_used: $json.engine_used,
    top_id: $json.top_id,
    top_probability: $json.top_probability,
    ranking: $json.ranking,
    request: $json.request,
    route_action: $json.route_action ?? $json.route,
    // Keep a copy of the VectorPrime payload + raw response for debugging.
    vp_payload: $json.vp_payload,
    vp_raw: $json.vp_raw,
    // Optional: demo payloads
    slack_message: $json.slack_message,
    backlog_record: $json.backlog_record,
    email: ($json.email_to ? { to: $json.email_to, subject: $json.email_subject, body: $json.email_body } : undefined),
  }
}];
